import{_ as t,o as a,c as r,a2 as s}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/introduction.md","filePath":"fr/guide/introduction.md"}'),n={name:"fr/guide/introduction.md"};function o(i,e,l,d,c,u){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="qu-est-ce-que-clearance" tabindex="-1">Qu&#39;est-ce que Clearance ? <a class="header-anchor" href="#qu-est-ce-que-clearance" aria-label="Permalink to &quot;Qu&#39;est-ce que Clearance ?&quot;">​</a></h2><p>Clearance est un panneau d&#39;administration prêt à l&#39;emploi pour les applications Laravel, construit au-dessus de <a href="https://github.com/spatie/laravel-permission" target="_blank" rel="noreferrer">spatie/laravel-permission</a>. Il ajoute un panneau Livewire 4 + Flux UI pour gérer les permissions, rôles, gardes et paramètres, plus une couche d&#39;autorisation contextuelle et des rôles plafonds - installable en une seule commande artisan, sans altérer aucune table de Spatie.</p><p>Clearance vous offre :</p><ul><li><strong>Un panneau d&#39;administration</strong> pour Permissions, Rôles, Gardes, Paramètres et un Tableau de bord - utilisez les routes prêtes à l&#39;emploi ou intégrez chaque composant Livewire individuellement.</li><li><strong>Une autorisation contextuelle</strong> - accordez un rôle ou une permission limité à une instance de modèle spécifique (un Store, un Tenant, un Project), avec <code>$user-&gt;canIn()</code>, les directives Blade <code>@canin</code>/<code>@hasrolein</code>, et un <code>ContextService</code> pour une utilisation en dehors du modèle User.</li><li><strong>Des rôles plafonds</strong> - un rôle peut déclarer un rôle parent dont l&#39;ensemble de permissions agit comme une limite supérieure ; un rôle enfant ne peut jamais dépasser son parent, contrôle appliqué automatiquement à chaque enregistrement.</li><li><strong>Des permissions d&#39;écriture fines</strong> - une permission <code>clearance-{section}-write</code> délégable par section du panneau, afin de pouvoir confier &quot;gérer les rôles&quot; sans confier également &quot;gérer les paramètres.&quot;</li><li><strong>Un Super Admin</strong> avec un contournement de Gate global optionnel, une détection d&#39;alias pour les rôles administrateur existants, et une promotion sûre et non destructive.</li><li><strong>Un module Utilisateurs</strong> (optionnel) - assignez des rôles globalement ou à un contexte spécifique, plus des surcharges de permissions par contexte, depuis un panneau par utilisateur.</li><li><strong>Un panneau Paramètres</strong> - nom d&#39;affichage, description, icône SVG assainie et couleur par rôle/garde ; un rôle par défaut configurable avec attribution automatique et attribution en masse.</li><li><strong>Une gestion des Gardes</strong> - gardes stockés en base de données, injectés dans <code>auth.guards</code> au démarrage, restreints à un ensemble de drivers en liste blanche.</li><li><strong>9 langues incluses</strong> (ar, en, es, fr, hi, it, pt, ru, zh), parité des clés testée.</li><li><strong>Des points d&#39;extension</strong> - le trait <code>HasClearance</code>, le trait <code>HasPermissionGroups</code>, le contrat <code>ClearanceContextable</code>, des composants Blade réutilisables.</li><li><strong>Un assainissement SVG</strong> - chaque icône fournie par l&#39;utilisateur passe par un assainisseur en liste blanche avant le stockage et au moment du rendu.</li><li><strong>Une sécurité renforcée</strong> - plafonds anti-élévation de privilèges sur chaque chemin d&#39;attribution de permission, surcharges de contexte à autorité de refus, espace de noms <code>clearance-*</code> protégé. Voir <a href="/clearance-docs/fr/guide/security.html">Sécurité</a>.</li></ul><h2 id="relation-avec-spatie-laravel-permission" tabindex="-1">Relation avec spatie/laravel-permission <a class="header-anchor" href="#relation-avec-spatie-laravel-permission" aria-label="Permalink to &quot;Relation avec spatie/laravel-permission&quot;">​</a></h2><p>Clearance ne remplace pas le package de permissions de Spatie - c&#39;est une couche d&#39;interface et d&#39;autorisation construite dessus. Les rôles et permissions restent les modèles <code>Role</code> et <code>Permission</code> de Spatie, toujours stockés dans les tables <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code> et <code>role_has_permissions</code> de Spatie. Clearance ne modifie jamais ces tables. Tout ce que Clearance ajoute - métadonnées d&#39;affichage, portée des rôles, plafonds, assignations contextuelles, surcharges par contexte - vit dans son propre ensemble de tables <code>clr_*</code>. Voir <a href="/clearance-docs/fr/guide/architecture.html">Architecture</a> pour le détail complet.</p><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dépendance</th><th>Version</th></tr></thead><tbody><tr><td>PHP</td><td>^8.3</td></tr><tr><td>Laravel</td><td>^11.0 | ^12.0 | ^13.0</td></tr><tr><td>spatie/laravel-permission</td><td>^6.0</td></tr><tr><td>livewire/livewire</td><td>^3.0 | ^4.0</td></tr><tr><td>livewire/flux</td><td>^2.14</td></tr></tbody></table><h2 id="concepts-cles" tabindex="-1">Concepts clés <a class="header-anchor" href="#concepts-cles" aria-label="Permalink to &quot;Concepts clés&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Résumé</th></tr></thead><tbody><tr><td>Permission</td><td>Une permission Spatie suivant la convention de nommage <code>group-action</code> (ex. <code>orders-create</code>). Accorde une capacité.</td></tr><tr><td>Portée du rôle</td><td>Chaque rôle est <code>global</code> (assigné directement, s&#39;applique partout) ou <code>contextual</code> (lié à des types de modèle spécifiques, assignable uniquement au sein d&#39;une instance de contexte).</td></tr><tr><td>Rôle plafond</td><td>Un rôle peut déclarer un rôle parent dont l&#39;ensemble de permissions constitue une limite supérieure - l&#39;enfant ne peut jamais la dépasser.</td></tr><tr><td>Contexte</td><td>Une instance de modèle (un Store, un Tenant, un Project) à laquelle un rôle ou une surcharge de permission peut être limité.</td></tr><tr><td>Surcharge</td><td>Une attribution ou un refus de permission <code>forced_on</code>/<code>forced_off</code> par utilisateur, par contexte - un refus l&#39;emporte toujours.</td></tr></tbody></table><p>Chacun de ces concepts dispose de sa propre page complète : <a href="/clearance-docs/fr/features/permissions.html">Permissions</a>, <a href="/clearance-docs/fr/features/roles.html">Rôles</a>, <a href="/clearance-docs/fr/features/contextual-authorization.html">Autorisation contextuelle</a>, <a href="/clearance-docs/fr/features/users.html">Utilisateurs</a>, <a href="/clearance-docs/fr/features/super-admin.html">Super Admin</a>.</p><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><p>Prêt à installer Clearance ? Continuez avec le <a href="/clearance-docs/fr/guide/installation.html">guide d&#39;installation</a>.</p>',14)])])}const h=t(n,[["render",o]]);export{m as __pageData,h as default};
